<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  login-lock-duration</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">15m</span></span>
